@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductService productService;

    public ProductController(ProductService productService) {
        this.productService = productService;
    }

    @GetMapping
    public List<Product> getProducts(
            @RequestParam(required = false) String category) {
        if (category != null) return productService.getByCategory(category);
        return productService.getAll();
    }
}

@PostMapping("/api/orders")
public ResponseEntity<Order> createOrder(@RequestBody @Valid Order order) {
    if (order.getItems() == null || order.getItems().isEmpty()) {
        return ResponseEntity.badRequest().build();
    }
    Order saved = orderService.save(order);
    return ResponseEntity.status(HttpStatus.CREATED).body(saved);
}

@GetMapping("/api/products/{id}")
public ResponseEntity<Product> getProduct(@PathVariable Long id) {
    return productService.findById(id)
        .map(ResponseEntity::ok)
        .orElse(ResponseEntity.notFound().build());
}

@PatchMapping("/api/customers/{id}/email")
public ResponseEntity<Customer> updateEmail(
        @PathVariable Long id,
        @RequestBody Map<String, String> body) {
    String newEmail = body.get("email");
    return customerService.updateEmail(id, newEmail)
        .map(ResponseEntity::ok)
        .orElse(ResponseEntity.notFound().build());
}

@Service
public class DiscountService {

    private final DiscountRepository discountRepository;

    public DiscountService(DiscountRepository discountRepository) {
        this.discountRepository = discountRepository;
    }

    public double applyDiscount(String code, double originalTotal) {
        return discountRepository.findByCode(code)
            .map(d -> originalTotal * (1 - d.getPercentage() / 100.0))
            .orElse(originalTotal);
    }
}

